import xml.etree.ElementTree as ET

def validate_xml(xml_data):
    root = ET.fromstring(xml_data)
    if root.tag != 'root':
        raise ValueError('Invalid root tag')
    
    for child in root:
        if child.tag not in ['item1', 'item2']:
            raise ValueError('Unknown tag in root')
            
    return True